var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님, 제가 돌아왔습니다.","JPN":"救世主様、ただいま戻りました。","ENG":"I have returned, Savior.","TWN":"我回來了，救贖者大人。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"발키리는 예정대로 차원의 미로를 헤매게 되었답니다.","JPN":"ヴァルキリーは予定通り、次元の迷路に閉じ込めました。","ENG":"Valkyrie is now lost in the maze of dimensions, as planned.","TWN":"女武神如我們計畫的那般迷失在次元迷宮裡了。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"더는 저희에게 위협이 되지 않겠지요.","JPN":"これ以上私たちの脅威にはならないでしょう。","ENG":"She shall no longer be a threat to us.","TWN":"她已經不再是個威脅。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이제 겁없이 성역에 발을 들인 늑대를 처리하시기만 하면……","JPN":"あとは身の程も知らず聖域に足を踏み入れた狼を始末すれば……","ENG":"Now, all that is left is to slay the brazen Wolf who entered the sanctuary–","TWN":"現在只要再解決掉膽敢踏足聖域的狼……"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"내숭은 그만둬. 사령술사.","JPN":"猫を被るのはやめろ。降霊術師。","ENG":"Drop the act, Necromancer.","TWN":"別裝了，死靈術師。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"당신이 찾는 구원자는 여기 없어.","JPN":"その救世主はここにいない。","ENG":"Your dear Savior isn't here.","TWN":"你的救贖者不在這裡。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신은……. 이방인의 호위로군요.","JPN":"あなたは……異邦人の護衛。","ENG":"You... You must be the outsider's bodyguard.","TWN":"你是……外邦人的護衛。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"다음부터는 미리 기척을 내 주시지요.","JPN":"次からは居るなら居ると言ってください。","ENG":"I kindly ask you to reveal your presence next time.","TWN":"拜託你下次提前給個動靜。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"시궁창의 쥐처럼 숨어 있다 나타나시면, 놀라서 저도 모르게 죽여 버릴지 모르니까요.","JPN":"ドブネズミのように見えないところから急に出てこられたら、驚いて思わず殺してしまうかもしれませんから。","ENG":"Should you continue to hide yourself like some vermin in the sewers, I might kill you by accident.","TWN":"像躲在臭水溝裡的老鼠一樣突然出現，沒有失手殺了你已經很不錯了。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그건 어릴 적 경험에서 우러나온 비유인가?","JPN":"それは子どもの頃の経験から言っているのか？","ENG":"Speaking from past experiences, huh?","TWN":"這個比喻是源於你的童年經歷嗎？"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……함부로 남의 속내를 엿보지 마세요.","JPN":"……勝手に人の心の中を覗かないでください。","ENG":"...Please do not read other people without their consent.","TWN":"……隨意窺探別人內心是不禮貌的行為。"},"stage":{"bg":"THRONE","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신들 중에 존중 받을 만한 자는 이 세계의 대적자뿐이란 걸 모르진 않으실 텐데요.","JPN":"あなた方の中で尊重に値するのは、この世界の敵対者のみであることをお忘れなく。","ENG":"Surely you are aware that the Antagonist is the only one worth our courtesy.","TWN":"你們中唯一值得尊重的人就是這個世界的敵對者了，你應該不會不知道吧。"},"stage":{"bg":"THRONE","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"과연 그 자가 당신의 실언까지 대신 책임지려고 나설까요?","JPN":"その方があなたの失言まで庇ってくれればいいですけどね。","ENG":"I doubt he would be willing to take responsibility for your wrongdoings.","TWN":"他真會願意出面替你的失言負責？"},"stage":{"bg":"THRONE","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"감추고 싶어하는 구석을 들췄다면 미안하게 됐어. 가끔 멋대로 이러거든.","JPN":"隠しておきたいことだったなら、悪かったな。つい口が滑った。","ENG":"My apologies if I brought up something you wanted to hide. I can't help it sometimes.","TWN":"如果恰好揭露了你的舊傷疤，那我很抱歉。有時候我是會控制不住這個能力。"},"stage":{"bg":"THRONE","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신의 사과 따위 필요없습니다. 그러니 묻는 말에나 대답하시죠.","JPN":"あなたに謝罪など求めていません。ですから質問にだけ答えてください。","ENG":"I do not need your apology. What I need is an answer to my question.","TWN":"我不需要你的道歉。所以，請回答我的問題。"},"stage":{"bg":"THRONE","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자께서는 어디로 가셨습니까? 대적자는요?","JPN":"救世主様はどちらへ？　敵対者は？","ENG":"Where did the Savior head to? And the Antagonist?","TWN":"救贖者大人去哪兒了？還有敵對者呢？"},"stage":{"bg":"THRONE","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"두 사람 다 행선지는 밝히지 않았어.","JPN":"二人とも行先は言っていなかった。","ENG":"Neither of them said where they were going.","TWN":"他們沒有透露目的地。"},"stage":{"bg":"THRONE","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};